import{_ as a,c as i,o,a2 as t}from"./chunks/framework.CIiVzG-O.js";const u=JSON.parse('{"title":"Privacy Policy","description":"","frontmatter":{},"headers":[],"relativePath":"guide/privacy.md","filePath":"guide/privacy.md","lastUpdated":1777014665000}'),r={name:"guide/privacy.md"};function s(n,e,l,c,h,d){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy Policy&quot;">​</a></h1><h2 id="data-collection" tabindex="-1">Data Collection <a class="header-anchor" href="#data-collection" aria-label="Permalink to &quot;Data Collection&quot;">​</a></h2><p>The developer does not collect any data from this app.</p><h3 id="information-we-do-not-collect" tabindex="-1">Information We Do Not Collect <a class="header-anchor" href="#information-we-do-not-collect" aria-label="Permalink to &quot;Information We Do Not Collect&quot;">​</a></h3><ul><li>Personal information</li><li>Usage statistics</li><li>Device information</li><li>Location data</li><li>Image content or metadata</li><li>Browsing history</li><li>Any other user data</li></ul><h3 id="chrome-extension" tabindex="-1">Chrome Extension <a class="header-anchor" href="#chrome-extension" aria-label="Permalink to &quot;Chrome Extension&quot;">​</a></h3><p>The Nicasa Chrome extension requests access to page content solely to extract image URLs for the image viewing functionality. The extension:</p><ul><li>Does not read or store browsing history</li><li>Does not track user behavior</li><li>Does not transmit any data to external servers</li><li>Only processes image URLs locally within your browser</li></ul><h3 id="local-processing" tabindex="-1">Local Processing <a class="header-anchor" href="#local-processing" aria-label="Permalink to &quot;Local Processing&quot;">​</a></h3><p>All image processing, editing, and viewing happens locally on your device. No images or data are uploaded to external servers.</p><h3 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h3><p>Nicasa requests the following permissions on macOS:</p><ul><li><strong>Screen Recording</strong>: Required for screenshot functionality</li><li><strong>Accessibility</strong>: Optional, used for overlay mode features</li><li><strong>Files and Folders</strong>: Access to user-selected directories for image browsing</li></ul><p>These permissions can be managed in System Settings &gt; Privacy &amp; Security.</p><h3 id="third-party-services" tabindex="-1">Third-Party Services <a class="header-anchor" href="#third-party-services" aria-label="Permalink to &quot;Third-Party Services&quot;">​</a></h3><p>Nicasa does not integrate with any third-party analytics, advertising, or data collection services.</p><h3 id="privacy-choices" tabindex="-1">Privacy Choices <a class="header-anchor" href="#privacy-choices" aria-label="Permalink to &quot;Privacy Choices&quot;">​</a></h3><p>If you wish to exercise privacy rights (for example: access, deletion, portability, or opt-out requests), or if you believe Nicasa has personal data about you, you can submit a request using one of the methods below:</p><ul><li>Email: <a href="mailto:nicasa@w3cub.com" target="_blank" rel="noreferrer">nicasa@w3cub.com</a></li><li>Open a privacy issue: <a href="https://github.com/nicasa-app/nicasa-support/issues" target="_blank" rel="noreferrer">https://github.com/nicasa-app/nicasa-support/issues</a></li><li>Use our hosted Privacy Choices page: /guide/privacy-choices</li></ul><p>Because Nicasa does not collect personal data as described above, many requests will be answered with a confirmation that no personal data is held. If we begin to collect personal data in future releases, this page and the hosted Privacy Choices form will provide a way to submit and track requests.</p><p>We aim to respond to legitimate privacy requests within 30 days.</p><h3 id="updates" tabindex="-1">Updates <a class="header-anchor" href="#updates" aria-label="Permalink to &quot;Updates&quot;">​</a></h3><p>This privacy policy may be updated with new versions of the application. Users will be notified of any significant changes.</p><h3 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to &quot;Contact&quot;">​</a></h3><p>For privacy-related questions, please contact us through the <a href="https://github.com/nicasa-app/nicasa-support/issues" target="_blank" rel="noreferrer">GitHub repository</a>.</p>',25)])])}const m=a(r,[["render",s]]);export{u as __pageData,m as default};
